                 "bool": {
                    "filter": {
                        "term": {
                          "field": "value"
                        }
                      },
                      "must_not": {
                        "term": {
                          "field": "value",
                          "field": "value2"
                        }
                      }
                    }
                  }
                }
                )`

Accroding to https://elasticsearch-py.readthedocs.io/en/master/api.html#elasticsearch.Elasticsearch.search it should work:

